/**
 * Get the compiled ErgoTree hex for a specific contract by name.
 *
 * @param name - The contract name (e.g. 'provider_registration')
 * @returns The compiled ErgoTree hex string
 * @throws {Error} If the contract name is not recognized
 */
export function getContract(name: ContractName): string {
  const hex = CONTRACTS[name];
  if (!hex) {
    throw new Error(`Unknown contract: ${name}`);
  }
  return hex;
}

export type { CompiledContracts, ContractName } from './types/contracts';
